mapper.select:
SELECT t.template_id, t.template_name, t.equipment_type, t.inspection_kind, (SELECT COUNT(*) FROM inspection_items i WHERE i.template_id = t.template_id) AS item_count, t.updated_at, t.sort_order FROM inspection_template t
AND t.equipment_type = #{equipmentType}
AND t.inspection_kind = #{inspectionKind}
ORDER BY t.sort_order ASC, t.template_id ASC
LIMIT #{limit} OFFSET #{offset}

